firmware_template.source:
#include "modbus_rtu.h"
#include <HardwareSerial.h>
#include <ModbusMaster.h>
#define DE_PIN 4
static HardwareSerial mbSerial(1);
static ModbusMaster node;
void _pre(){digitalWrite(DE_PIN,HIGH);}
void _post(){digitalWrite(DE_PIN,LOW);}
void modbus_setup(){pinMode(DE_PIN,OUTPUT);mbSerial.begin(9600,SERIAL_8N1,16,17);node.begin(1,mbSerial);node.preTransmission(_pre);node.postTransmission(_post);Serial.println("[modbus] OK");}
uint16_t modbus_read_register(uint8_t s,uint16_t r){node.begin(s,mbSerial);uint8_t res=node.readHoldingRegisters(r,1);return res==node.ku8MBSuccess?node.getResponseBuffer(0):0xFFFF;}
bool modbus_write_register(uint8_t s,uint16_t r,uint16_t v){node.begin(s,mbSerial);return node.writeSingleRegister(r,v)==node.ku8MBSuccess;}
